#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

#define MAX_N 100001

// Use a fixed size for the arrays
long long int dp[MAX_N];
int a[MAX_N];

int compare(const void *a, const void *b) {
    return (*(int *)a - *(int *)b);
}

int main() {
    int t, sum_n = 0;
    scanf("%d", &t);
    assert(1 <= t && t <= 100000);

    while (t--) {
        int n, d;
        scanf("%d %d", &n, &d);
        sum_n += n;
        assert(1 <= n && n <= 100000);
        assert(1 <= d && d <= 100000);

        dp[0] = 0;
        a[0] = -123456; // This initialization is not necessary for the logic

        for (int i = 1; i <= n; i++) {
            scanf("%d", &a[i]);
            assert(1 <= a[i] && a[i] <= 100000);
        }

        // Sort the array a using qsort
        qsort(a + 1, n, sizeof(int), compare);

        for (int i = 1; i <= n; i++) {
            assert(1 <= a[i] && a[i] <= 100000);
            dp[i] = dp[i - 1]; // Carry forward the previous value

            // Check for the difference condition
            if (a[i] - a[i - 1] < d) {
                // Ensure i > 1 before accessing dp[i - 2]
                long long int newValue = (i > 1 ? dp[i - 2] + a[i] + a[i - 1] : 0);
                dp[i] = (dp[i] > newValue) ? dp[i] : newValue; // Use ternary operator correctly
            }
        }

        printf("%lld\n", dp[n]);
    }

    assert(1 <= sum_n && sum_n <= 500000);
    return 0;
}

