import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        // Initialize Scanner for input
        Scanner sc = new Scanner(System.in);

        // Read the number of test cases
        int t = sc.nextInt();
        assert (1 <= t && t <= 100000);

        // Initialize variables for sum of n
        int sum_n = 0;

        while (t-- > 0) {
            // Read n and d
            int n = sc.nextInt();
            int d = sc.nextInt();
            sum_n += n;
            assert (1 <= n && n <= 100000);
            assert (1 <= d && d <= 100000);

            long[] dp = new long[n + 1];  // DP array
            int[] a = new int[n + 1];      // Array to store inputs

            dp[0] = 0;
            a[0] = -123456;  // Initial value for a[0]

            // Read array values
            for (int i = 1; i <= n; i++) {
                a[i] = sc.nextInt();
                assert (1 <= a[i] && a[i] <= 100000);
            }

            // Sort the array
            Arrays.sort(a, 1, n + 1);

            for (int i = 1; i <= n; i++) {
                assert (1 <= a[i] && a[i] <= 100000);
                dp[i] = dp[i - 1]; // Update dp[i]

                // Check the condition and update dp[i] accordingly
                if (a[i] - a[i - 1] < d) {
                    dp[i] = Math.max(dp[i], dp[i - 2] + a[i] + a[i - 1]);
                }
            }

            // Output the result for the current test case
            System.out.println(dp[n]);
        }

        // Assert the sum of n
        assert (1 <= sum_n && sum_n <= 500000);
        sc.close(); // Close the scanner
    }
}

