function solution(N, d) {
    N.sort((a, b) => b - a); // Sort in descending order
    let x = 0;
    let i = 0;

    while (i < N.length - 1) {
        if (N[i] - N[i + 1] < d) {
            x += (N[i] + N[i + 1]);
            i += 1; // Move to the next pair
        }
        i += 1; // Move to the next element
    }

    return x;
}

function main() {
    const input = require('readline').createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let lines = [];
    input.on('line', (line) => {
        lines.push(line);
    });

    input.on('close', () => {
        let index = 0;
        const T = parseInt(lines[index++]); // Read number of test cases

        let results = [];
        for (let i = 0; i < T; i++) {
            const [n, d] = lines[index++].split(' ').map(Number); // Read n and d for each test case
            const N = lines[index++].split(' ').map(Number); // Read the array N
            results.push(solution(N, d)); // Call the solution function and store the result
        }

        console.log(results.join('\n')); // Print all results
    });
}

